@app.post("/v1/models/{model_id}/predict", response_model=PredictResponse)
async def predict(
    model_id: str,
    req: PredictRequest = Body(...),
    x_tenant_id: Optional[str] = Header(default=None, alias="X-Tenant-ID"),
):
    tenant_id = _require_tenant(x_tenant_id)
    model_obj = _get_model(tenant_id, model_id)

    method_name = req.method
    if not method_name:
        if hasattr(model_obj, "predict") and callable(getattr(model_obj, "predict")):
            method_name = "predict"
        elif callable(model_obj):
            method_name = "__call__"
        else:
            raise HTTPException(status_code=400, detail="Model has no predict() and is not callable")

    kwargs = req.kwargs or {}

    try:
        if method_name == "__call__":
            if not callable(model_obj):
                raise HTTPException(status_code=400, detail="Model is not callable")
            output = model_obj(req.inputs, **kwargs)
        else:
            fn = getattr(model_obj, method_name, None)
            if fn is None or not callable(fn):
                raise HTTPException(status_code=400, detail=f"Model has no callable method '{method_name}'")
            output = fn(req.inputs, **kwargs)
    except HTTPException:
        raise
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Inference error: {type(e).__name__}: {str(e)}")

    return PredictResponse(tenant_id=tenant_id, model_id=model_id, output=output)


@app.post("/v1/models/{model_id}/reload")
def reload_model_from_disk(
    model_id: str,
    x_tenant_id: Optional[str] = Header(default=None, alias="X-Tenant-ID"),
):
    tenant_id = _require_tenant(x_tenant_id)
    meta = _get_meta(tenant_id, model_id)
    path = meta.get("path")
    if not path or not os.path.exists(path):
        raise HTTPException(status_code=404, detail="Model file not found on disk")

    try:
        with open(path, "rb") as f:
            model_obj = pickle.load(f)
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Failed to deserialize model: {type(e).__name__}: {str(e)}")

    with _lock:
        _models.setdefault(tenant_id, {})[model_id] = model_obj

    return {"tenant_id": tenant_id, "model_id": model_id, "reloaded": True}


